package com.archivenexus.backend.ai;
import com.archivenexus.backend.ai.ManufacturingAiModels.*;import com.archivenexus.backend.domain.DomainModels.*;import com.archivenexus.backend.service.NexusStateService;import org.springframework.stereotype.Component;import java.util.*;
@Component public class InventoryAgent implements ManufacturingAgent{
 private final NexusStateService nexus;public InventoryAgent(NexusStateService nexus){this.nexus=nexus;}
 public String getName(){return "InventoryAgent";}public boolean supports(Intent intent){return intent==Intent.INVENTORY;}public int getPriority(){return 40;}
 public AgentResult analyze(AgentContext context){long started=System.nanoTime();List<InventoryItem> items=nexus.inventoryItems();if(items.isEmpty())return new AgentResult(getName(),Intent.INVENTORY,"판단할 재고 데이터가 부족함",List.of(),List.of(),0,elapsed(started),AgentExecutionStatus.INSUFFICIENT_DATA,null,false);List<InventoryItem> risks=items.stream().filter(i->i.quantity()<=i.safetyStock()).toList();long outbound=nexus.inventoryTransactions().stream().filter(t->context.selectedFactoryId()==null||context.selectedFactoryId().equals(t.factoryId())).filter(t->"OUT".equalsIgnoreCase(t.type())).mapToLong(InventoryTransaction::quantity).sum();List<AgentEvidence> evidence=List.of(new AgentEvidence("INVENTORY","안전재고 이하 품목",risks.size()+"건","inventoryItems"),new AgentEvidence("INVENTORY","선택 범위 출고량",String.valueOf(outbound),"inventoryTransactions"));List<String> actions=risks.isEmpty()?List.of():List.of("안전재고 이하 품목의 보충 발주와 생산 투입 우선순위를 검토하세요.");return new AgentResult(getName(),Intent.INVENTORY,risks.isEmpty()?"현재 안전재고 위험이 확인되지 않았습니다.":"안전재고 이하 품목 "+risks.size()+"건이 생산 연속성에 영향을 줄 수 있습니다.",evidence,actions,risks.isEmpty()?0.82:0.9,elapsed(started),AgentExecutionStatus.COMPLETED,null,!risks.isEmpty());}
 private long elapsed(long started){return(System.nanoTime()-started)/1_000_000;}
}
